using System;
using System.Collections.Generic;
using System.Linq;
using System.Security.Claims;
using System.Text;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Http;
using Microsoft.IdentityModel.Tokens;

namespace MyApp.Middleware
{
    public class JwtAuthenticationMiddleware
    {
        private readonly RequestDelegate _next;

        public JwtAuthenticationMiddleware(RequestDelegate next)
        {
            _next = next;
        }

        public async Task InvokeAsync(HttpContext context)
        {
            var header = context.Request.Headers["Authorization"];

            if (header.Count == 0)
            {
                await _next(context);
                return;
            }

            var authHeader = Encoding.UTF8.DecodeSubstring(header[0]);
            if (!authHeader.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase))
            {
                await HandleUnauthorizedRequest(context);
                return;
            }

            var token = authHeader.Substring("Bearer ".Length).Trim();

            try
            {
                var tokenHandler = new JwtSecurityTokenHandler();
                var key = Encoding.ASCII.GetBytes("Your_Secret_Key"); // Replace with your secret key
                var tokenValid = tokenHandler.CanValidateToken &&
                    tokenHandler.ValidateToken(token, new TokenValidationParameters
                    {
                        IssuerSigningKey = new SymmetricSecurityKey(key),
                        ValidateIssuerSigningKey = true,
                        ValidateAudience = false,
                        ValidateIssuer = false,
                        RequireExpirationTime = true,
                        ClockSkew = TimeSpan.Zero
                    }, out var validatedToken);

                if (!tokenValid)
                {
                    await HandleUnauthorizedRequest(context);
                    return;
                }

                var claimsPrincipal = tokenHandler.CreateClaimsPrincipal(validatedToken);
                var identity = new ClaimsIdentity(claimsPrincipal.Claims, "Jwt");
                var principal = new ClaimsPrincipal(identity);
                context.User = principal;
            }
            catch (Exception ex)
            {
                await HandleUnauthorizedRequest(context);
            }

            await _next(context);
        }

        private async Task HandleUnauthorizedRequest(HttpContext context)
        {
            context.Response.ContentType = "application/json";
            context.Response.StatusCode = StatusCodes.Status401Unauthorized;
            await context.Response.WriteAsync("Unauthorized");
        }
    }
